#include<bits/stdc++.h>
using namespace std;
int n,qian[100010],hou[100010];
struct node
{
    int s,a;
    bool operator<(const node&b)const
    {
        return a>b.a;
    }
}a[100010];
int sum[100010];
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i].s);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i].a);
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        qian[i]=max(qian[i-1],a[i].s);
        sum[i]=sum[i-1]+a[i].a;
    }
    for(int i=n;i>=1;i--)
    {
        hou[i]=max(hou[i+1],a[i].s*2+a[i].a);
    }
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",max(sum[i]+qian[i]*2,sum[i-1]+hou[i]));
    }
    return 0;
}
